mapper.select:
select mpc.id, mpc.meal_plan_id, mpc.customer_id, mpc.customer_name, mpc.phone, cp.customer_code, mpc.order_id, mpc.parent_package_id, mpc.child_package_id, mpc.status, mpc.is_verified, mpc.verification_time, mpc.verification_operator, mpc.fail_reason, mpc.meat_required_count, mpc.veg_required_count, mpc.include_soup, mpc.include_rice, mpc.supplementary_main_count, mpc.supplementary_side_count, mpc.supplementary_veg_count, mpc.supplementary_rice_count, mpc.supplementary_soup_count, cp.special_requirements, mpc.create_by, mpc.update_by, mpc.deleted, mpc.create_time, mpc.update_time from meal_plan_customer mpc left join customer_profile cp on mpc.customer_id = cp.id where mpc.deleted = 0 and mpc.meal_plan_id in
#{mealPlanId}
order by mpc.meal_plan_id asc, mpc.id asc
